1	export type Cell = readonly [x: number, y: number];
2	
3	const toKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: readonly Cell[] = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	const livesNextGeneration = (isAlive: boolean, neighborCount: number): boolean =>
12	  neighborCount === 3 || (isAlive && neighborCount === 2);
13	
14	type NeighborEntry = { cell: Cell; neighborCount: number };
15	
16	const countNeighbors = (cells: readonly Cell[]): Map<string, NeighborEntry> => {
17	  const entries = new Map<string, NeighborEntry>();
18	  for (const [x, y] of cells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const cell: Cell = [x + dx, y + dy];
21	      const key = toKey(cell);
22	      const entry = entries.get(key);
23	      if (entry) entry.neighborCount++;
24	      else entries.set(key, { cell, neighborCount: 1 });
25	    }
26	  }
27	  return entries;
28	};
29	
30	export function nextGeneration(cells: readonly Cell[]): readonly Cell[] {
31	  const aliveKeys = new Set(cells.map(toKey));
32	  const result: Cell[] = [];
33	  for (const [key, { cell, neighborCount }] of countNeighbors(cells)) {
34	    if (livesNextGeneration(aliveKeys.has(key), neighborCount)) result.push(cell);
35	  }
36	  return result;
37	}
38

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die from underpopulation — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life is unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	    expect(new Set(result.map(([x, y]) => `${x},${y}`))).toEqual(
17	      new Set(["0,0", "1,0", "0,1", "1,1"])
18	    );
19	    expect(result).toHaveLength(4);
20	  });
21	  it("blinker oscillates vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
22	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
23	    expect(new Set(result.map(([x, y]) => `${x},${y}`))).toEqual(
24	      new Set(["-1,1", "0,1", "1,1"])
25	    );
26	    expect(result).toHaveLength(3);
27	  });
28	  it("live cell with 2 neighbors survives (rule 2) — middle of horizontal row of 3", () => {
29	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
30	    const keys = new Set(result.map(([x, y]) => `${x},${y}`));
31	    expect(keys.has("1,0")).toBe(true);
32	  });
33	  it("live cell with more than 3 neighbors dies from overpopulation — center of filled 3x3", () => {
34	    const cells: [number, number][] = [
35	      [0, 0], [1, 0], [2, 0],
36	      [0, 1], [1, 1], [2, 1],
37	      [0, 2], [1, 2], [2, 2],
38	    ];
39	    const result = nextGeneration(cells);
40	    const keys = new Set(result.map(([x, y]) => `${x},${y}`));
41	    expect(keys.has("1,1")).toBe(false);
42	  });
43	  it("dead cell with exactly 3 live neighbors becomes alive (reproduction) — L-shape grows", () => {
44	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
45	    const keys = new Set(result.map(([x, y]) => `${x},${y}`));
46	    expect(keys.has("1,1")).toBe(true);
47	  });
48	  it("handles negative coordinates — blinker at negative origin", () => {
49	    const result = nextGeneration([[-5, -5], [-5, -4], [-5, -3]]);
50	    expect(new Set(result.map(([x, y]) => `${x},${y}`))).toEqual(
51	      new Set(["-6,-4", "-5,-4", "-4,-4"])
52	    );
53	    expect(result).toHaveLength(3);
54	  });
55	});
